-- Ghana Tertiary UniConnect Dataset - part 1
-- Run parts sequentially in Supabase SQL Editor.

-- Ghana Tertiary UniConnect Starter Dataset
-- Generated from ghana-tertiary-uniconnect-dataset CSV files.
-- Run AFTER 012_regent_academic_seed.sql.

alter table public.universities add column if not exists source_id text;
alter table public.universities add column if not exists category text;
alter table public.universities add column if not exists region text;
alter table public.universities add column if not exists country text default 'Ghana';
alter table public.universities add column if not exists status text default 'active';
alter table public.faculties add column if not exists source_id text;
alter table public.departments add column if not exists source_id text;

create table if not exists public.courses (
  id uuid primary key default gen_random_uuid(),
  source_id text unique,
  university_id uuid references public.universities(id) on delete cascade,
  faculty_id uuid references public.faculties(id) on delete set null,
  department_id uuid references public.departments(id) on delete cascade,
  code text,
  name text not null,
  level text,
  credits integer,
  semester text,
  course_type text default 'core',
  created_at timestamptz default now()
);

create table if not exists public.app_catalog_items (
  id text primary key,
  type text not null,
  name text not null,
  created_at timestamptz default now()
);

alter table public.courses enable row level security;
alter table public.app_catalog_items enable row level security;

drop policy if exists "courses read same university" on public.courses;
create policy "courses read same university" on public.courses for select to authenticated using (university_id = public.current_user_university_id() or public.current_user_role() = 'super_admin');
drop policy if exists "courses manage admins" on public.courses;
create policy "courses manage admins" on public.courses for all to authenticated using (public.current_user_role() = 'super_admin' or (public.current_user_role() = 'university_admin' and university_id = public.current_user_university_id())) with check (public.current_user_role() = 'super_admin' or (public.current_user_role() = 'university_admin' and university_id = public.current_user_university_id()));
drop policy if exists "catalog read" on public.app_catalog_items;
create policy "catalog read" on public.app_catalog_items for select to authenticated using (true);
drop policy if exists "catalog manage admins" on public.app_catalog_items;
create policy "catalog manage admins" on public.app_catalog_items for all to authenticated using (public.current_user_role() in ('super_admin','university_admin')) with check (public.current_user_role() in ('super_admin','university_admin'));

create unique index if not exists idx_universities_source_id on public.universities(source_id) where source_id is not null;
create unique index if not exists idx_faculties_source_id on public.faculties(source_id) where source_id is not null;
create unique index if not exists idx_departments_source_id on public.departments(source_id) where source_id is not null;
create index if not exists idx_courses_department on public.courses(department_id);
create index if not exists idx_courses_university on public.courses(university_id);

